const url = $.input.apiUrl;
const method = ($.input.httpMethod || 'GET').toUpperCase();
const headersStr = $.input.headers || '';
const body = $.input.requestBody || '';

let cmd = 'curl -sS -w "\n---HTTP_CODE:%{http_code}---\n---TOTAL_TIME:%{time_total}---\n---SIZE:%{size_download}---" -m 30';
cmd += ' -X ' + method;

if (headersStr) {
  try {
    const h = JSON.parse(headersStr);
    Object.entries(h).forEach(([k, v]) => {
      cmd += ' -H "' + k + ': ' + v + '"';
    });
  } catch(e) {}
}

if (body && (method === 'POST' || method === 'PUT' || method === 'PATCH')) {
  cmd += ' -H "Content-Type: application/json"';
  cmd += " -d '" + body.replace(/'/g, "'\\''") + "'";
}

cmd += ' "' + url + '"';

return { curlCommand: cmd, url, method };

const raw = $.steps.callApi.output || '';
let httpCode = '';
let totalTime = '';
let size = '';
let body = raw;

const codeMatch = raw.match(/---HTTP_CODE:(\d+)---/);
if (codeMatch) httpCode = codeMatch[1];
const timeMatch = raw.match(/---TOTAL_TIME:([\d.]+)---/);
if (timeMatch) totalTime = timeMatch[1];
const sizeMatch = raw.match(/---SIZE:(\d+)---/);
if (sizeMatch) size = sizeMatch[1];

body = body.replace(/\n---HTTP_CODE:\d+---/, '').replace(/\n---TOTAL_TIME:[\d.]+---/, '').replace(/\n---SIZE:\d+---/, '').trim();

let isJson = false;
let prettyBody = body;
try { const parsed = JSON.parse(body); isJson = true; prettyBody = JSON.stringify(parsed, null, 2); } catch(e) {}

return {
  httpCode: httpCode || 'unknown',
  totalTime: totalTime || 'unknown',
  size: size || '0',
  isJson,
  body: prettyBody.slice(0, 25000),
  bodyPreview: prettyBody.slice(0, 3000),
  url: $.steps.buildCurlCommand.output.url,
  method: $.steps.buildCurlCommand.output.method
};

const r = $.steps.parseResponse.output;

let prompt = 'You are an API testing expert. Analyze the following API response and provide a comprehensive report.

';
prompt += 'API ENDPOINT: ' + r.method + ' ' + r.url + '
';
prompt += 'HTTP STATUS: ' + r.httpCode + '
';
prompt += 'RESPONSE TIME: ' + r.totalTime + ' seconds
';
prompt += 'RESPONSE SIZE: ' + r.size + ' bytes
';
prompt += 'IS JSON: ' + r.isJson + '

';
prompt += 'RESPONSE BODY:
' + r.body + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Analyze the response structure and data types
';
prompt += '- Assess if the HTTP status code is appropriate
';
prompt += '- Evaluate response time performance
';
prompt += '- Identify any data quality issues or anomalies
';
prompt += '- Check for common API best practices (pagination, error handling, etc.)
';
prompt += '- Rate the API response quality overall
';
prompt += '- Use Slack mrkdwn: *bold* (NOT **bold**), _italic_, numbered lists

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "statusAssessment": "is the status code appropriate and why",
';
prompt += '  "responseStructure": { "type": "object|array|string", "fieldCount": 0, "nestedLevels": 0, "fields": ["field1: type"] },
';
prompt += '  "performanceRating": "excellent|good|acceptable|slow|poor",
';
prompt += '  "dataQuality": ["observation 1", "observation 2"],
';
prompt += '  "bestPractices": { "met": ["practice 1"], "missing": ["practice 1"] },
';
prompt += '  "issues": ["issue 1"],
';
prompt += '  "overallRating": "A|B|C|D|F",
';
prompt += '  "summary": "one-paragraph summary of the API response quality",
';
prompt += '  "recommendations": ["recommendation 1"]
';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { summary: raw, statusAssessment: '', responseStructure: {}, performanceRating: 'unknown', dataQuality: [], bestPractices: { met: [], missing: [] }, issues: [], overallRating: '?', recommendations: [] }; }

const ai = $.steps.parseAI.output;
const r = $.steps.parseResponse.output;

const ratingEmoji = { 'A': ':star:', 'B': ':white_check_mark:', 'C': ':ok:', 'D': ':warning:', 'F': ':x:' };

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'API Response Analysis', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Endpoint:* `' + r.method + ' ' + r.url + '`\n*Status:* ' + r.httpCode + ' | *Time:* ' + r.totalTime + 's | *Size:* ' + r.size + ' bytes | *Rating:* ' + (ratingEmoji[ai.overallRating] || ':grey_question:') + ' ' + (ai.overallRating || '?') } });
blocks.push({ type: 'divider' });

if (ai.summary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary*\n' + ai.summary.slice(0, 2900) } });
  blocks.push({ type: 'divider' });
}

if (ai.statusAssessment) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Status Assessment*\n' + ai.statusAssessment.slice(0, 1500) } });
}

if (ai.responseStructure && ai.responseStructure.fields) {
  let structText = '*Response Structure:* ' + (ai.responseStructure.type || 'unknown') + ' with ' + (ai.responseStructure.fieldCount || 0) + ' fields\n';
  (ai.responseStructure.fields || []).slice(0, 15).forEach(f => { structText += '  - ' + f + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: structText.slice(0, 2900) } });
}

const perfEmoji = { excellent: ':rocket:', good: ':white_check_mark:', acceptable: ':ok:', slow: ':snail:', poor: ':x:' };
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Performance:* ' + (perfEmoji[ai.performanceRating] || '') + ' ' + (ai.performanceRating || 'unknown') + ' (' + r.totalTime + 's)' } });
blocks.push({ type: 'divider' });

if (ai.bestPractices) {
  let bpText = '';
  if (ai.bestPractices.met && ai.bestPractices.met.length > 0) {
    bpText += ':white_check_mark: *Best practices met:*\n';
    ai.bestPractices.met.forEach(p => { bpText += '  - ' + p + '\n'; });
  }
  if (ai.bestPractices.missing && ai.bestPractices.missing.length > 0) {
    bpText += ':x: *Missing best practices:*\n';
    ai.bestPractices.missing.forEach(p => { bpText += '  - ' + p + '\n'; });
  }
  if (bpText) blocks.push({ type: 'section', text: { type: 'mrkdwn', text: bpText.slice(0, 2900) } });
}

if (ai.recommendations && ai.recommendations.length > 0) {
  let recText = ':bulb: *Recommendations:*\n';
  ai.recommendations.forEach((r, i) => { recText += (i + 1) + '. ' + r + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: recText.slice(0, 2900) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'API Testing powered by Claude AI | One CLI' }] });

const fallback = 'API Analysis: ' + r.method + ' ' + r.url + ' - Status ' + r.httpCode + ' - Rating ' + (ai.overallRating || '?');
return { blocks, fallback };
